        } else {
            row.steps.push(DowngraderPlanStep::new(
                DowngraderPlanStepKind::CreateCurrentBackup,
                format!(
                    "Create backup {} from {}.",
                    row.plan.current_backup_name, row.plan.display_name
                ),
