            target,
            PlatformErrorKind::ParseError,
            format!(
                "{} returned data that could not be understood.",
                operation.label()
            ),
        )
        .with_diagnostic(diagnostic)
    }

    /// Adds non-user-facing diagnostic text for logs or tests.

