component DowngraderLogRowItem inherits Rectangle {
    in property <DowngraderLogUiRow> entry;

    min-height: 18px;

    Text {
        text: root.entry.message;
        color: root.entry.level == "good" ? #8fdc8f :
            root.entry.level == "bad" ? #ff7b7b :
            #8ecbff;
        font-size: 11px;
        wrap: word-wrap;
    }
}

component DowngraderProgressBar inherits Rectangle {
    in property <float> percent: 0;

    height: 10px;
    background: #303030;
    border-color: #484848;
    border-width: 1px;

    Rectangle {
        x: 1px;
        y: 1px;
        height: parent.height - 2px;
        width: (parent.width - 2px) * root.percent / 100;
        background: #4da3ff;
    }
}

// The Tk reference uses Toplevel grab plus WM_DELETE/Escape veto while patching.
// Slint markup is kept as a source contract: runtime code must route platform
// close/Escape requests into modal-close-requested() and honor close-blocked
// while a confirmed Downgrader run is active.
export component DowngraderWindow inherits Window {
    in-out property <[DowngraderStatusUiRow]> current-game-status-rows;
    in-out property <[DowngraderStatusUiRow]> current-creation-kit-status-rows;
    in-out property <string> selected-target: "old_gen";
    in-out property <bool> keep-backups: true;
    in-out property <bool> delete-patches: false;
    in-out property <[DowngraderPlanUiRow]> plan-rows;
    in-out property <bool> plan-visible: false;
    in-out property <string> confirmation-state: "idle";
    in-out property <string> plan-confirmation-text: "Review the plan, then click Patch All again to confirm.";
    in-out property <[DowngraderLogUiRow]> log-rows;
    in-out property <string> log-text: "Patches will be downloaded and applied as-needed.";
    in-out property <float> progress-percent: 0;
    in-out property <string> progress-text: "";
    in-out property <bool> patch-enabled: false;
    in-out property <bool> about-enabled: true;
    in-out property <bool> controls-enabled: true;
    in-out property <bool> close-blocked: false;
    in-out property <string> close-blocked-text: "Patching is in progress. Close is disabled until patching finishes.";

    callback target-selected(string);
    callback option-toggled(string, bool);
    callback patch-requested();
    callback confirm-requested();
    callback about-requested();
    callback modal-close-requested();

    title: "Downgrader";
    width: 600px;
    height: 334px;

    Rectangle {
        background: #202020;

        VerticalLayout {
            padding: 8px;
            spacing: 6px;
            alignment: start;

            HorizontalLayout {
                spacing: 8px;
                alignment: start;

                VerticalLayout {
                    spacing: 6px;
                    alignment: start;

                    DowngraderStatusGroup {
                        title: "Current Game";
                        fixed-file-labels: "Fallout4.exe:\nFallout4Launcher.exe:\nsteam_api64.dll:";
                        rows: root.current-game-status-rows;
                    }

                    DowngraderStatusGroup {
                        title: "Current Creation Kit";
                        fixed-file-labels: "CreationKit.exe:\nArchive2.exe:\nArchive2Interop.dll:";
                        rows: root.current-creation-kit-status-rows;
                    }
                }

                VerticalLayout {
                    spacing: 6px;
                    alignment: start;
                    width: 142px;

                    GroupBox {
                        title: "Desired Version";
                        height: 92px;

                        VerticalLayout {
                            padding: 6px;
                            spacing: 6px;
                            alignment: start;

                            DowngraderOptionRadio {
                                text: "Old-Gen";
                                target-id: "old_gen";
                                checked: root.selected-target == "old_gen";
                                enabled: root.controls-enabled;
                                selected(target_id) => {
                                    root.selected-target = target_id;
                                    root.target-selected(target_id);
                                }
                            }

                            DowngraderOptionRadio {
                                text: "Next-Gen";
                                target-id: "next_gen";
                                checked: root.selected-target == "next_gen";
                                enabled: root.controls-enabled;
                                selected(target_id) => {
                                    root.selected-target = target_id;
                                    root.target-selected(target_id);
                                }
                            }
                        }
                    }

                    GroupBox {
                        title: "Options";
                        height: 92px;

                        VerticalLayout {
                            padding: 6px;
                            spacing: 6px;
                            alignment: start;

                            DowngraderOptionCheck {
                                text: "Keep Backups";
                                option-id: "keep_backups";
                                checked <=> root.keep-backups;
                                enabled: root.controls-enabled;
                                toggled(option_id, enabled) => {
                                    root.option-toggled(option_id, enabled);
                                }
                            }

                            DowngraderOptionCheck {
                                text: "Delete Patches";
                                option-id: "delete_patches";
                                checked <=> root.delete-patches;
                                enabled: root.controls-enabled;
                                toggled(option_id, enabled) => {
                                    root.option-toggled(option_id, enabled);
                                }
                            }
                        }
                    }
                }

                VerticalLayout {
                    spacing: 6px;
                    alignment: start;
                    width: 86px;

                    Button {
                        text: "Patch\n All";
                        enabled: root.patch-enabled;
                        height: 92px;
                        clicked => {
                            if (root.confirmation-state == "needs-confirmation") {
                                root.confirm-requested();
                            } else {
